class Solution:
    def countRangeSum(self, nums: list[int], lower: int, upper: int) -> int:
        n = len(nums)
        prefix_sums = [0] * (n + 1)
        for i in range(n):
            prefix_sums[i+1] = prefix_sums[i] + nums[i]

        def merge_sort_and_count(start: int, end: int) -> int:
            if end - start <= 1:
                return 0

            mid = (start + end) // 2

            count = merge_sort_and_count(start, mid) + merge_sort_and_count(mid, end)

            ptr1 = mid
            ptr2 = mid

            for i in range(start, mid):
                while ptr1 < end and prefix_sums[ptr1] < prefix_sums[i] + lower:
                    ptr1 += 1
                while ptr2 < end and prefix_sums[ptr2] <= prefix_sums[i] + upper:
                    ptr2 += 1

                count += (ptr2 - ptr1)

            merged_list = []
            left_ptr = start
            right_ptr = mid

            while left_ptr < mid and right_ptr < end:
                if prefix_sums[left_ptr] <= prefix_sums[right_ptr]:
                    merged_list.append(prefix_sums[left_ptr])
                    left_ptr += 1
                else:
                    merged_list.append(prefix_sums[right_ptr])
                    right_ptr += 1

            while left_ptr < mid:
                merged_list.append(prefix_sums[left_ptr])
                left_ptr += 1

            while right_ptr < end:
                merged_list.append(prefix_sums[right_ptr])
                right_ptr += 1

            for k in range(len(merged_list)):
                prefix_sums[start + k] = merged_list[k]

            return count

        return merge_sort_and_count(0, n + 1)
